def lossless_float_to_int(funcname, func, argname, arg):

    if not isinstance(arg, float):
        return arg

    arg_as_int = int(arg)
    if arg == arg_as_int:
        warnings.warn(
            "{f} expected an int for argument {name!r}, but got float {arg}."
            " Coercing to int.".format(
                f=funcname,
                name=argname,
                arg=arg,
            ),
        )
        return arg_as_int

    raise TypeError(arg)

def intent_verified(hub, callback_url, mode, topic_url, lease_seconds):

    challenge = uuid4()
    params = {
        'hub.mode': mode,
        'hub.topic': topic_url,
        'hub.challenge': challenge,
        'hub.lease_seconds': lease_seconds,
    }
    try:
        response = request_url(hub.config, 'GET', callback_url, params=params)
        assert response.status_code == 200 and response.text == challenge
    except requests.exceptions.RequestException as e:
        warn("Cannot verify subscriber intent", e)
    except AssertionError as e:
        warn(INTENT_UNVERIFIED % (response.status_code, response.content), e)
    else:
        return True
    return False

